// This class acts as an interface
class Flyable {
  void fly() {}
  int get altitude;
}

// Bird implements the Flyable interface
class Bird implements Flyable {
  @override
  void fly() {
    print('Bird is flying');
  }

  @override
  int get altitude => 1000;
}

void main() {
  Bird bird = Bird();
  bird.fly();
  print('Altitude: ${bird.altitude}');
}

class Swimmable {
  void swim() {}
}

class Walkable {
  void walk() {}
}

class Duck implements Swimmable, Walkable {
  @override
  void swim() {
    print('Duck swims');
  }

  @override
  void walk() {
    print('Duck walks');
  }
}

void main() {
  Duck duck = Duck();
  duck.swim();
  duck.walk();
}

abstract class Drawable {
  void draw(); // abstract
  void info() {
    print('This is a drawable object');
  }
}

class Circle implements Drawable {
  @override
  void draw() {
    print('Drawing a circle');
  }

  @override
  void info() {
    print('Circle info'); // Must implement even though it had a body
  }
}

// Define several interfaces (as classes)
class Printable {
  void printData() {}
}

class Storable {
  void save() {}
  void load() {}
}

class Serializable {
  String toJson() => '';
}

// A class that implements multiple interfaces
class Document implements Printable, Storable, Serializable {
  String content;

  Document(this.content);

  @override
  void printData() {
    print('Printing document: $content');
  }

  @override
  void save() {
    print('Saving document...');
  }

  @override
  void load() {
    print('Loading document...');
  }

  @override
  String toJson() {
    return '{"content": "$content"}';
  }
}

void main() {
  Document doc = Document('Hello, Dart!');
  doc.printData();
  doc.save();
  print('JSON: ${doc.toJson()}');
}

